-- Seed: Blender BOM components, extracted from 'Copy of BOMS for Alyssa (003).xlsx'
-- (Data sheet, Work Centre = '05-BLENDER BIG' / '05-BLENDER SMALL'), 2026-07-13.
-- ingredient_column is a starting guess (description match) -- correct it on the
-- Blends page if wrong. Initial load only -- that page is the source of truth after this.
on conflict (bom_id, line_nbr) do update set
  output_item_id = excluded.output_item_id,
  output_description = excluded.output_description,
  work_centre = excluded.work_centre,
  component_item_id = excluded.component_item_id,
  component_description = excluded.component_description,
  qty_required = excluded.qty_required,
  warehouse = excluded.warehouse,
  uom = excluded.uom,
  updated_at = now();
